  "bad":[.85,.95,.02,.02,.02],
  "okay":[0.02,0.25,0.95,.65,.35],
  "good":[.02,.05,.55,.95,.93],
  "amazing":[.02,.02,.02,.65,0.95]
}
var meaning = function(utterance, state){ return flip(literalSemantics[utterance][state - 1]) }
var lambda = 1.25
var valueFunction = function(s){ return lambda * s }
var listener0 = cache(function(utterance) {
  return Infer({model: function(){
    var state = uniformDraw(states)
    var m = meaning(utterance, state)
    condition(m)
    return state
  }})
})
var alpha = 10
var speaker1 = cache(function(state, phi) {
  return Infer({model: function(){
    var utterance = uniformDraw(utterances)
    var L0_posterior = listener0(utterance)
    var utility = {
      epistemic: L0_posterior.score(state),
      social: expectation(L0_posterior, valueFunction)
    }
    var speakerUtility = phi * utility.epistemic + (1 - phi) * utility.social
    factor(alpha * speakerUtility)
    return utterance
  }})
})
var pragmaticListener = function(utterance) {
  return Infer({model: function(){
    var state = uniformDraw(states)
    var phi = uniformDraw([0.1, 0.3, 0.5, 0.7, 0.9])
    var S1 = speaker1(state, phi)
    observe(S1, utterance)
    return { state: state, phi: phi }
  }})
}
var posterior = pragmaticListener("terrible")
var marginalize = function(dist, key) { return Infer({model: function(){ return sample(dist)[key] }}) }
var ANSWER = expectation(marginalize(posterior, "state"))

